import React, { useState, useMemo } from 'react';
import { useApp } from '../contexts/AppContext';
import { ChevronUp, ChevronDown, ReceiptText } from 'lucide-react';

export default function Faturamento() {
  const { vendas, loading } = useApp();
  const [busca, setBusca] = useState('');
  const [sortConfig, setSortConfig] = useState({ key: 'id', direction: 'desc' });

  // Filtro por ID do Pedido
  const vendasFiltradas = useMemo(() => {
    let result = vendas.filter(v => v.id.toString().includes(busca));
    if (sortConfig.key) {
      result.sort((a, b) => {
        if (a[sortConfig.key] < b[sortConfig.key]) return sortConfig.direction === 'asc' ? -1 : 1;
        if (a[sortConfig.key] > b[sortConfig.key]) return sortConfig.direction === 'asc' ? 1 : -1;
        return 0;
      });
    }
    return result;
  }, [vendas, busca, sortConfig]);

  const handleSort = (key) => {
    setSortConfig(prev => ({
      key,
      direction: prev.key === key && prev.direction === 'asc' ? 'desc' : 'asc'
    }));
  };

  if (loading) return <div className="mt-24 text-center animate-pulse">Carregando faturamento...</div>;

  return (
    <main className="mt-24 container mx-auto p-4">
      <div className="flex flex-col md:flex-row justify-between items-center mb-6 gap-4">
        <h2 className="text-2xl font-bold flex items-center gap-2">
          <ReceiptText className="text-blue-600" /> Histórico de Vendas
        </h2>
        <input 
          type="text" 
          placeholder="Buscar pelo número do pedido..." 
          className="border p-2 rounded-lg w-full md:w-80 shadow-sm focus:ring-2 focus:ring-blue-500 outline-none"
          onChange={(e) => setBusca(e.target.value)}
        />
      </div>

      <div className="overflow-x-auto bg-white rounded-xl shadow-lg border border-gray-100">
        <table className="w-full text-left">
          <thead className="bg-gray-50 border-b">
            <tr>
              {['id', 'data', 'valor_total'].map((col) => (
                <th key={col} className="p-4 cursor-pointer hover:bg-gray-100 transition" onClick={() => handleSort(col)}>
                  <div className="flex items-center gap-1 text-xs font-bold text-gray-500 uppercase">
                    {col.replace('_', ' ')}
                    {sortConfig.key === col && (sortConfig.direction === 'asc' ? <ChevronUp size={14}/> : <ChevronDown size={14}/>)}
                  </div>
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {vendasFiltradas.map(venda => (
              <tr key={venda.id} className="border-b hover:bg-blue-50/50 transition">
                <td className="p-4 font-medium text-blue-600">#{venda.id}</td>
                <td className="p-4 text-gray-600">{new Date(venda.data).toLocaleDateString('pt-BR')}</td>
                <td className="p-4 font-bold text-green-600">R$ {venda.valor_total?.toFixed(2)}</td>
              </tr>
            ))}
          </tbody>
        </table>
        {vendasFiltradas.length === 0 && <p className="p-10 text-center text-gray-400">Nenhuma venda encontrada.</p>}
      </div>
    </main>
  );
}
